// models/orders.js - Order CRUD operations with transactions
const db = require('../db');
const {
  validateUUID,
  validateNumber,
  validateOrderStatus,
  validateSortColumn,
  validateSortDirection,
  validatePagination,
  validatePositiveInteger,
  ValidationError,
} = require('../validators');

const OrdersModel = {
  async create({ userId, items }) {
    const validatedUserId = validateUUID(userId);

    if (!Array.isArray(items) || items.length === 0 || items.length > 50) {
      throw new ValidationError('Items must be a non-empty array with at most 50 items');
    }

    const validatedItems = items.map((item, index) => ({
      productId: validateUUID(item.productId),
      quantity: validatePositiveInteger(item.quantity, `items[${index}].quantity`),
    }));

    // SECURE: Use transaction to ensure atomicity
    return db.transaction(async (client) => {
      // Verify all products exist and have sufficient stock
      const productIds = validatedItems.map((item) => item.productId);
      const productsResult = await client.query(
        `SELECT id, price, stock FROM products WHERE id = ANY($1) FOR UPDATE`,
        [productIds]
      );

      const productsMap = new Map(productsResult.rows.map((p) => [p.id, p]));

      let total = 0;
      const orderItems = [];

      for (const item of validatedItems) {
        const product = productsMap.get(item.productId);
        if (!product) {
          throw new ValidationError(`Product ${item.productId} not found`);
        }
        if (product.stock < item.quantity) {
          throw new ValidationError(`Insufficient stock for product ${item.productId}`);
        }
        const itemTotal = parseFloat(product.price) * item.quantity;
        total += itemTotal;
        orderItems.push({ ...item, price: parseFloat(product.price), itemTotal });
      }

      // Create order
      const orderResult = await client.query(
        `INSERT INTO orders (user_id, total, status, created_at, updated_at)
         VALUES ($1, $2, 'pending', NOW(), NOW())
         RETURNING id, user_id, total, status, created_at, updated_at`,
        [validatedUserId, Math.round(total * 100) / 100]
      );
      const order = orderResult.rows[0];

      // Create order items and update stock
      for (const item of orderItems) {
        await client.query(
          `INSERT INTO order_items (order_id, product_id, quantity, unit_price, total_price)
           VALUES ($1, $2, $3, $4, $5)`,
          [order.id, item.productId, item.quantity, item.price, item.itemTotal]
        );

        await client.query(
          `UPDATE products SET stock = stock - $1, updated_at = NOW() WHERE id = $2`,
          [item.quantity, item.productId]
        );
      }

      // Fetch order items for response
      const itemsResult = await client.query(
        `SELECT oi.id, oi.product_id, p.name as product_name, oi.quantity, oi.unit_price, oi.total_price
         FROM order_items oi
         JOIN products p ON p.id = oi.product_id
         WHERE oi.order_id = $1`,
        [order.id]
      );

      return { ...order, items: itemsResult.rows };
    });
  },

  async findById(id, { userId } = {}) {
    const validatedId = validateUUID(id);
    let query = `SELECT o.id, o.user_id, o.total, o.status, o.created_at, o.updated_at
                 FROM orders o WHERE o.id = $1`;
    const params = [validatedId];

    // SECURE: If userId is provided, enforce ownership check
    if (userId) {
      const validatedUserId = validateUUID(userId);
      query += ' AND o.user_id = $2';
      params.push(validatedUserId);
    }

    const orderResult = await db.query(query, params);
    if (orderResult.rows.length === 0) return null;

    const order = orderResult.rows[0];

    const itemsResult = await db.query(
      `SELECT oi.id, oi.product_id, p.name as product_name, oi.quantity, oi.unit_price, oi.total_price
       FROM order_items oi
       JOIN products p ON p.id = oi.product_id
       WHERE oi.order_id = $1`,
      [order.id]
    );

    return { ...order, items: itemsResult.rows };
  },

  async listByUser(userId, { page, limit, sortBy = 'created_at', sortDir = 'DESC' } = {}) {
    const validatedUserId = validateUUID(userId);
    const pagination = validatePagination(page, limit);
    const validatedSort = validateSortColumn('orders', sortBy);
    const validatedDir = validateSortDirection(sortDir);
    const offset = (pagination.page - 1) * pagination.limit;

    const [dataResult, countResult] = await Promise.all([
      db.query(
        `SELECT id, user_id, total, status, created_at, updated_at
         FROM orders WHERE user_id = $1
         ORDER BY ${validatedSort} ${validatedDir}
         LIMIT $2 OFFSET $3`,
        [validatedUserId, pagination.limit, offset]
      ),
      db.query('SELECT COUNT(*) as total FROM orders WHERE user_id = $1', [validatedUserId]),
    ]);

    return {
      data: dataResult.rows,
      pagination: {
        page: pagination.page,
        limit: pagination.limit,
        total: parseInt(countResult.rows[0].total, 10),
      },
    };
  },

  async updateStatus(id, { status, userId }) {
    const validatedId = validateUUID(id);
    const validatedStatus = validateOrderStatus(status);

    let query = `UPDATE orders SET status = $1, updated_at = NOW() WHERE id = $2`;
    const params = [validatedStatus, validatedId];

    // SECURE: Enforce ownership if userId provided
    if (userId) {
      const validatedUserId = validateUUID(userId);
      query += ' AND user_id = $3';
      params.push(validatedUserId);
    }

    query += ' RETURNING id, user_id, total, status, created_at, updated_at';

    const result = await db.query(query, params);
    return result.rows[0] || null;
  },

  async delete(id) {
    const validatedId = validateUUID(id);

    return db.transaction(async (client) => {
      await client.query('DELETE FROM order_items WHERE order_id = $1', [validatedId]);
      const result = await client.query('DELETE FROM orders WHERE id = $1 RETURNING id', [validatedId]);
      return result.rowCount > 0;
    });
  },
};

