// middleware/errorHandler.js - Secure error handling
const { ValidationError } = require('../validators');
const { DatabaseError } = require('../db');

function errorHandler(err, req, res, next) {
  // SECURE: Do not expose internal error details to clients
  if (err instanceof ValidationError) {
    return res.status(400).json({
      error: 'Validation Error',
      message: err.message,
    });
  }

  if (err instanceof DatabaseError) {
    // SECURE: Log the original error internally but return generic message to client
    console.error('Database error:', err.originalMessage);
    return res.status(500).json({
      error: 'Internal Server Error',
      message: 'A database error occurred. Please try again later.',
    });
  }

  // SECURE: Generic error response for unexpected errors
  console.error('Unexpected error:', err.message, err.stack);
  return res.status(500).json({
    error: 'Internal Server Error',
    message: 'An unexpected error occurred.',
  });
}

module.exports = { errorHandler };


// middleware/rateLimiter.js - Basic rate limiting
const rateLimitMap = new Map();

function rateLimit({ windowMs = 60000, maxRequests = 100 } = {}) {
  return (req, res, next) => {
    const key = req.ip || req.connection.remoteAddress;
    const now = Date.now();
    const windowStart = now - windowMs;

    if (!rateLimitMap.has(key)) {
      rateLimitMap.set(key, []);
    }

    const requests = rateLimitMap.get(key).filter((time) => time > windowStart);
    requests.push(now);
    rateLimitMap.set(key, requests);

    if (requests.length > maxRequests) {
      return res.status(429).json({
        error: 'Too Many Requests',
        message: 'Rate limit exceeded. Please try again later.',
      });
    }

    next();
  };
}

// Cleanup old entries periodically
setInterval(() => {
  const now = Date.now();
  for (const [key, times] of rateLimitMap.entries()) {
    const recent = times.filter((t) => t > now - 60000);
    if (recent.length === 0) {
      rateLimitMap.delete(key);
    } else {
      rateLimitMap.set(key, recent);
    }
  }
}, 60000);

module.exports = { rateLimit };


