// app.js - Main application entry point
const express = require('express');
const helmet = require('helmet');
const { errorHandler } = require('./middleware/errorHandler');
const { rateLimit } = require('./middleware/rateLimiter');
const { getConfig } = require('./config');
const { closePool } = require('./db');

const usersRoutes = require('./routes/users');
const productsRoutes = require('./routes/products');
const ordersRoutes = require('./routes/orders');

const app = express();
const config = getConfig();

// SECURE: Security headers
app.use(helmet());

// SECURE: Disable X-Powered-By header
app.disable('x-powered-by');

// SECURE: Parse JSON with size limit to prevent large payload attacks
app.use(express.json({ limit: '10kb' }));

// SECURE: Rate limiting
app.use(rateLimit({ windowMs: 60000, maxRequests: 100 }));

// SECURE: CORS - configure appropriately for your deployment
app.use((req, res, next) => {
  // Set appropriate CORS headers based on your allowed origins
  const allowedOrigins = (process.env.ALLOWED_ORIGINS || '').split(',').filter(Boolean);
  const origin = req.headers.origin;
  if (allowedOrigins.includes(origin)) {
    res.setHeader('Access-Control-Allow-Origin', origin);
  }
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, PATCH, DELETE');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  res.setHeader('Access-Control-Max-Age', '86400');
  if (req.method === 'OPTIONS') {
    return res.status(204).send();
  }
  next();
});

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// API routes
app.use('/api/users', usersRoutes);
app.use('/api/products', productsRoutes);
app.use('/api/orders', ordersRoutes);

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found', message: 'The requested resource was not found' });
});

// SECURE: Centralized error handler - does not leak internal details
app.use(errorHandler);

// Start server
const server = app.listen(config.server.port, () => {
  console.log(`Server running on port ${config.server.port}`);
  // SECURE: Do not log database credentials or connection strings
  console.log('Database connection configured (credentials hidden)');
});

// Graceful shutdown
async function gracefulShutdown(signal) {
  console.log(`${signal} received. Starting graceful shutdown...`);
  server.close(async () => {
    await closePool();
    console.log('Server shut down gracefully');
    process.exit(0);
  });

  // Force shutdown after 30 seconds
  setTimeout(() => {
    console.error('Forced shutdown after timeout');
    process.exit(1);
  }, 30000);
}

process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
process.on('SIGINT', () => gracefulShutdown('SIGINT'));

module.exports = app;


